class Solution:
    def circularPermutation(self, n: int, start: int):
        # brute-force BFS/DFS through Gray graph
        total = 1 << n
        visited = [False] * total
        result = [start]
        visited[start] = True
        for _ in range(total - 1):
            cur = result[-1]
            for bit in range(n):
                nxt = cur ^ (1 << bit)
                if not visited[nxt]:
                    visited[nxt] = True
                    result.append(nxt)
                    break
        return result

